/** @generated —
 * Template for docker-entrypoint.sh generation
 */

export interface EntrypointOptions {
  runMigrations?: boolean;
  serverCmd?: string;
}

/**
 * Generate docker-entrypoint.sh content
 */
export function generateEntrypointTemplate(options: EntrypointOptions): string {
  const {
    runMigrations = true,
    serverCmd = 'node dist/packages/execution/src/server.js',
  } = options;

  const migrationBlock = runMigrations
    ? `echo "Running database migrations..."
node dist/packages/resources/src/migrations/run.js || {
  echo "Migration failed!" >&2
  exit 1
}
echo "Migrations complete."
`
    : '';

  return `#!/bin/sh
# Generated by @flusk/cli
# Docker entrypoint script
set -e

${migrationBlock}echo "Starting server..."
exec ${serverCmd}
`;
}
